function Sparkles() {
  const particles = Array.from({ length: 18 }, (_, i) => ({
    id: i, left: Math.random() * 100, delay: Math.random() * 8,
    dur: 6 + Math.random() * 8, size: 3 + Math.random() * 6, type: i % 3,
  }));
  return (
    <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0, overflow: "hidden" }}>
      {particles.map((p) => (
        <div key={p.id} style={{ position: "absolute", left: `${p.left}%`, bottom: "-10px", width: p.size, height: p.size, borderRadius: "50%", background: p.type === 0 ? COLORS.lavender : p.type === 1 ? COLORS.peach : COLORS.pink, opacity: 0.3, animation: `floatUp ${p.dur}s ${p.delay}s infinite ease-in` }} />
      ))}
      <style>{`@keyframes floatUp { 0% { transform: translateY(0) rotate(0deg); opacity: 0; } 10% { opacity: 0.35; } 90% { opacity: 0.15; } 100% { transform: translateY(-105vh) rotate(360deg); opacity: 0; } }`}</style>
    </div>
  );
}

