function BookingCalendar() {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(null);
  const [selectedTime, setSelectedTime] = useState(null);
  const [selectedType, setSelectedType] = useState(null);
  const [bookingStep, setBookingStep] = useState(0);
  const [formData, setFormData] = useState({ name: "", email: "", phone: "", notes: "" });
  const [submitted, setSubmitted] = useState(false);

  const [storedSlots, setStoredSlots] = useState({});
  const [slotsLoaded, setSlotsLoaded] = useState(false);
  useEffect(() => {
    (async () => {
      try {
        const { data } = await supabase.from("calendar_slots").select("*");
        if (data) {
          const obj = {};
          data.forEach(row => { obj[row.date] = row.times; });
          setStoredSlots(obj);
        }
      } catch (e) {}
      setSlotsLoaded(true);
    })();
  }, []);
  const [bookings, setBookings] = useState([]);
  useEffect(() => {
    (async () => {
      try {
        const { data } = await supabase.from("bookings").select("date, time_slot");
        if (data) setBookings(data);
      } catch (e) {}
    })();
  }, [submitted]);
  const monthKey = `${currentMonth.getFullYear()}-${String(currentMonth.getMonth()+1).padStart(2,"0")}`;
  const availableDays = Object.keys(storedSlots).filter(k => k.startsWith(monthKey)).map(k => parseInt(k.split("-")[2]));
  const getTimeSlotsForDate = (day) => {
    const key = `${monthKey}-${String(day).padStart(2,"0")}`;
    const allSlots = storedSlots[key] || [];
    const bookedTimes = bookings.filter(b => b.date === key).map(b => b.time_slot);
    return allSlots.filter(t => !bookedTimes.includes(t));
  };
  const getBookedCount = (day) => {
    const key = `${monthKey}-${String(day).padStart(2,"0")}`;
    return bookings.filter(b => b.date === key).length;
  };
  const timeSlots = selectedDate ? getTimeSlotsForDate(selectedDate) : [];
  const monthName = currentMonth.toLocaleString("default", { month: "long", year: "numeric" });
  const daysInMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).getDate();
  const firstDayOfWeek = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1).getDay();
  const today = new Date();
  const isPast = (day) => new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day) < new Date(today.getFullYear(), today.getMonth(), today.getDate());

  if (submitted) {
    return (
      <Section id="booking" bg={COLORS.bgAlt}>
        <div style={{ textAlign: "center", padding: "60px 20px" }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>✨</div>
          <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: 32, color: COLORS.text, margin: "0 0 16px" }}>Booking Request Received!</h2>
          <p style={{ fontFamily: "'Nunito', sans-serif", fontSize: 16, color: COLORS.textLight, lineHeight: 1.7, maxWidth: 500, margin: "0 auto" }}>
            Thank you, {formData.name}! I'll confirm your {SESSION_TYPES.find(s => s.id === selectedType)?.name} on{" "}
            {selectedDate && new Date(currentMonth.getFullYear(), currentMonth.getMonth(), selectedDate).toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric" })} at {selectedTime} within 24 hours.
          </p>
          <button onClick={() => { setSubmitted(false); setBookingStep(0); setSelectedDate(null); setSelectedTime(null); setSelectedType(null); setFormData({ name: "", email: "", phone: "", notes: "" }); }} style={{ fontFamily: "'Nunito', sans-serif", marginTop: 28, padding: "12px 32px", borderRadius: 50, border: `2px solid ${COLORS.lavender}`, background: "transparent", color: COLORS.lavender, fontSize: 14, fontWeight: 700, cursor: "pointer" }}>Book Another Session</button>
        </div>
      </Section>
    );
  }

  return (
    <Section id="booking" bg={COLORS.bgAlt}>
      <SectionTitle sub="Choose your session type, pick a date and time, and let the healing begin.">✦ Book a Session</SectionTitle>
      <div className="session-grid" style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: 20, marginBottom: 48 }}>
        {SESSION_TYPES.map((s) => (
          <div key={s.id} onClick={() => { setSelectedType(s.id); setBookingStep(1); }} style={{ background: COLORS.white, borderRadius: 20, padding: 28, cursor: "pointer", boxShadow: selectedType === s.id ? `0 8px 32px ${s.color}44` : `0 4px 20px ${COLORS.shadow}`, border: selectedType === s.id ? `2.5px solid ${s.color}` : "2.5px solid transparent", transition: "all 0.3s" }} onMouseEnter={(e) => { if (selectedType !== s.id) e.currentTarget.style.transform = "translateY(-4px)"; }} onMouseLeave={(e) => { e.currentTarget.style.transform = ""; }}>
            <div style={{ fontSize: 36, marginBottom: 12 }}>{s.icon}</div>
            <h3 style={{ fontFamily: "'Playfair Display', serif", fontSize: 20, color: COLORS.text, margin: "0 0 4px" }}>{s.name}</h3>
            <div style={{ fontFamily: "'Nunito', sans-serif", fontSize: 13, color: s.color, fontWeight: 700, marginBottom: 12 }}>{s.duration} · {s.price}</div>
            <p style={{ fontFamily: "'Nunito', sans-serif", fontSize: 14, color: COLORS.textMuted, lineHeight: 1.6, margin: 0 }}>{s.desc}</p>
          </div>
        ))}
      </div>

      {selectedType && (
        <div style={{ display: "flex", justifyContent: "center", gap: 8, marginBottom: 32, alignItems: "center", flexWrap: "wrap" }}>
          {["Session Type", "Date & Time", "Your Info"].map((step, i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{ width: 28, height: 28, borderRadius: "50%", background: bookingStep >= i ? `linear-gradient(135deg, ${COLORS.lavender}, ${COLORS.peach})` : COLORS.lavenderLight, color: bookingStep >= i ? COLORS.white : COLORS.textMuted, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Nunito', sans-serif", fontSize: 12, fontWeight: 700 }}>{i + 1}</div>
              <span style={{ fontFamily: "'Nunito', sans-serif", fontSize: 13, color: bookingStep >= i ? COLORS.text : COLORS.textMuted, fontWeight: 600 }}>{step}</span>
              {i < 2 && <div style={{ width: 30, height: 1, background: COLORS.lavenderLight }} />}
            </div>
          ))}
        </div>
      )}

      {bookingStep >= 1 && (
        <div style={{ background: COLORS.white, borderRadius: 24, padding: "clamp(20px, 4vw, 36px)", boxShadow: `0 8px 40px ${COLORS.shadow}`, maxWidth: 500, margin: "0 auto 32px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
            <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1))} style={{ background: "none", border: "none", fontSize: 20, cursor: "pointer", color: COLORS.textLight, padding: 8 }}>‹</button>
            <h3 style={{ fontFamily: "'Playfair Display', serif", fontSize: 20, color: COLORS.text, margin: 0 }}>{monthName}</h3>
            <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1))} style={{ background: "none", border: "none", fontSize: 20, cursor: "pointer", color: COLORS.textLight, padding: 8 }}>›</button>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 4, marginBottom: 8 }}>
            {["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"].map((d) => (<div key={d} style={{ textAlign: "center", fontFamily: "'Nunito', sans-serif", fontSize: 12, fontWeight: 700, color: COLORS.textMuted, padding: 6 }}>{d}</div>))}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 4 }}>
            {Array.from({ length: firstDayOfWeek }, (_, i) => <div key={`e-${i}`} />)}
            {Array.from({ length: daysInMonth }, (_, i) => {
              const day = i + 1; const avail = availableDays.includes(day) && !isPast(day); const sel = selectedDate === day;
              return (<button key={day} disabled={!avail} onClick={() => { setSelectedDate(day); setSelectedTime(null); }} style={{ width: "100%", aspectRatio: "1", borderRadius: "50%", border: "none", background: sel ? `linear-gradient(135deg, ${COLORS.lavender}, ${COLORS.peach})` : avail ? COLORS.lavenderPale : "transparent", color: sel ? COLORS.white : avail ? COLORS.text : COLORS.textMuted + "66", fontFamily: "'Nunito', sans-serif", fontSize: 14, fontWeight: sel ? 700 : 500, cursor: avail ? "pointer" : "default", transition: "all 0.2s", opacity: avail ? 1 : 0.4 }}>{day}</button>);
            })}
          </div>
          <div style={{ marginTop: 16, display: "flex", gap: 16, justifyContent: "center" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}><div style={{ width: 10, height: 10, borderRadius: "50%", background: COLORS.lavenderPale }} /><span style={{ fontFamily: "'Nunito', sans-serif", fontSize: 11, color: COLORS.textMuted }}>Available</span></div>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}><div style={{ width: 10, height: 10, borderRadius: "50%", background: `linear-gradient(135deg, ${COLORS.lavender}, ${COLORS.peach})` }} /><span style={{ fontFamily: "'Nunito', sans-serif", fontSize: 11, color: COLORS.textMuted }}>Selected</span></div>
          </div>
          {selectedDate && (
            <div style={{ marginTop: 24 }}>
              <h4 style={{ fontFamily: "'Playfair Display', serif", fontSize: 16, color: COLORS.text, marginBottom: 12 }}>Available Times</h4>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 8 }}>
                {timeSlots.map((t) => (<button key={t} onClick={() => { setSelectedTime(t); setBookingStep(2); }} style={{ padding: "10px 8px", borderRadius: 12, border: selectedTime === t ? "none" : `1.5px solid ${COLORS.lavenderLight}`, background: selectedTime === t ? `linear-gradient(135deg, ${COLORS.lavender}, ${COLORS.peach})` : COLORS.white, color: selectedTime === t ? COLORS.white : COLORS.text, fontFamily: "'Nunito', sans-serif", fontSize: 13, fontWeight: 600, cursor: "pointer", transition: "all 0.2s" }}>{t}</button>))}
              </div>
            </div>
          )}
        </div>
      )}

      {bookingStep >= 2 && selectedTime && (
        <div style={{ background: COLORS.white, borderRadius: 24, padding: "clamp(24px, 4vw, 40px)", boxShadow: `0 8px 40px ${COLORS.shadow}`, maxWidth: 500, margin: "0 auto" }}>
          <h3 style={{ fontFamily: "'Playfair Display', serif", fontSize: 20, color: COLORS.text, marginTop: 0, marginBottom: 20 }}>Complete Your Booking</h3>
          <div style={{ background: COLORS.lavenderPale, borderRadius: 14, padding: 16, marginBottom: 24, fontFamily: "'Nunito', sans-serif", fontSize: 14, color: COLORS.text, lineHeight: 1.6 }}>
            <strong>{SESSION_TYPES.find((s) => s.id === selectedType)?.name}</strong><br />
            {new Date(currentMonth.getFullYear(), currentMonth.getMonth(), selectedDate).toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", year: "numeric" })} at {selectedTime}
          </div>
          {[{ key: "name", label: "Full Name", type: "text", placeholder: "Your name" }, { key: "email", label: "Email", type: "email", placeholder: "your@email.com" }, { key: "phone", label: "Phone", type: "tel", placeholder: "(555) 123-4567" }].map((f) => (
            <div key={f.key} style={{ marginBottom: 18 }}>
              <label style={{ fontFamily: "'Nunito', sans-serif", fontSize: 13, fontWeight: 700, color: COLORS.text, display: "block", marginBottom: 6 }}>{f.label}</label>
              <input type={f.type} placeholder={f.placeholder} value={formData[f.key]} onChange={(e) => setFormData({ ...formData, [f.key]: e.target.value })} style={{ width: "100%", padding: "12px 16px", borderRadius: 12, border: `1.5px solid ${COLORS.lavenderLight}`, fontFamily: "'Nunito', sans-serif", fontSize: 14, color: COLORS.text, outline: "none", boxSizing: "border-box" }} onFocus={(e) => (e.target.style.borderColor = COLORS.lavender)} onBlur={(e) => (e.target.style.borderColor = COLORS.lavenderLight)} />
            </div>
          ))}
          <div style={{ marginBottom: 24 }}>
            <label style={{ fontFamily: "'Nunito', sans-serif", fontSize: 13, fontWeight: 700, color: COLORS.text, display: "block", marginBottom: 6 }}>Notes (optional)</label>
            <textarea placeholder="Anything I should know? First time? Specific intentions?" value={formData.notes} onChange={(e) => setFormData({ ...formData, notes: e.target.value })} rows={3} style={{ width: "100%", padding: "12px 16px", borderRadius: 12, border: `1.5px solid ${COLORS.lavenderLight}`, fontFamily: "'Nunito', sans-serif", fontSize: 14, color: COLORS.text, outline: "none", resize: "vertical", boxSizing: "border-box" }} />
          </div>
          <button onClick={() => setSubmitted(true)} disabled={!formData.name || !formData.email || !formData.phone} style={{ width: "100%", padding: "14px", borderRadius: 50, border: "none", background: formData.name && formData.email && formData.phone ? `linear-gradient(135deg, ${COLORS.lavender}, ${COLORS.peach})` : COLORS.lavenderLight, color: COLORS.white, fontFamily: "'Nunito', sans-serif", fontSize: 15, fontWeight: 700, cursor: formData.name && formData.email && formData.phone ? "pointer" : "default", letterSpacing: "0.04em" }}>Confirm Booking ✦</button>
        </div>
      )}
    </Section>
  );
}

